from flask import Flask, request, jsonify
from flask_limiter import Limiter
from flask_sqlalchemy import SQLAlchemy
import secrets
import smtplib

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)
limiter = Limiter(app, key_func=lambda: request.remote_addr)

class PasswordResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    token = db.Column(db.String(120), nullable=False)

db.create_all()

def send_reset_email(email, token):
    reset_link = f"http://example.com/reset-password?token={token}"
    # Configure your SMTP server and send the email
    with smtplib.SMTP('localhost') as server:
        server.sendmail('noreply@example.com', email, f'Subject: Password Reset\n\nClick here to reset your password: {reset_link}')

@app.route('/request-password-reset', methods=['POST'])
@limiter.limit("5 per hour")
def request_password_reset():
    email = request.json.get('email')
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    token = secrets.token_urlsafe(16)
    reset_token = PasswordResetToken(email=email, token=token)
    db.session.add(reset_token)
    db.session.commit()

    send_reset_email(email, token)
    return jsonify({'message': 'Password reset link sent if email exists'}), 200

if __name__ == '__main__':
    app.run(debug=True)